// Récupérer tous les sujets existants
const existingItems = $input.all();
const existingTitles = existingItems.map(item => item.json.title || '').filter(t => t);
const existingSlugs = existingItems.map(item => item.json.slug || '').filter(s => s);

// Types d'articles possibles
const articleTypes = [
  { type: 'temoignage', label: 'un témoignage client fictif mais réaliste', category: 'Inspirations' },
  { type: 'conseil', label: 'un article de conseils pratiques', category: 'Conseils' },
  { type: 'anecdote', label: 'une anecdote de chantier intéressante', category: 'Inspirations' },
  { type: 'recommandation', label: 'des recommandations pour choisir son sol', category: 'Conseils' },
  { type: 'info_produit', label: 'une présentation produit/technique Chemtec', category: 'Conseils' }
];

// Choisir un type aléatoire
const chosen = articleTypes[Math.floor(Math.random() * articleTypes.length)];

// Choisir une image aléatoire
const images = ['garage2.webp', 'shoowroom2.webp', 'entrepot2.webp', 'apres.webp', 'equipehorizontale.webp'];
const chosenImage = images[Math.floor(Math.random() * images.length)];

// Villes belges pour SEO local
const villes = ['Bruxelles', 'Liège', 'Charleroi', 'Namur', 'Mons', 'Ixelles', 'Gand', 'Anvers', 'Louvain-la-Neuve', 'Waterloo'];
const ville = villes[Math.floor(Math.random() * villes.length)];

// Date du jour
const today = new Date().toISOString().split('T')[0];

// Construire la liste des sujets déjà traités
const dejaTraites = existingTitles.length > 0 
  ? existingTitles.map((t, i) => `- ${t}`).join('\n')
  : '(aucun sujet encore traité)';

return [{
  json: {
    articleType: chosen.type,
    articleTypeLabel: chosen.label,
    category: chosen.category,
    image: chosenImage,
    ville: ville,
    today: today,
    dejaTraites: dejaTraites,
    existingSlugs: existingSlugs
  }
}];

// Parser la réponse Claude
const response = $input.first().json;
const textContent = response.content[0].text;

// Extraire le JSON de la réponse
let article;
try {
  // Nettoyer si Claude met des backticks
  let cleaned = textContent.trim();
  if (cleaned.startsWith('```')) {
    cleaned = cleaned.replace(/```json?\n?/g, '').replace(/```$/g, '').trim();
  }
  article = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Impossible de parser la réponse Claude: ' + textContent.substring(0, 200));
}

// Récupérer les données du noeud précédent via le workflow
const prepData = $('Préparer le prompt').first().json;
const today = prepData.today;
const image = prepData.image;
const articleType = prepData.articleType;

// Valider et nettoyer le slug
let slug = article.slug
  .toLowerCase()
  .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-z0-9-]/g, '-')
  .replace(/-+/g, '-')
  .replace(/^-|-$/g, '');

// Vérifier que le slug n'existe pas déjà
const existingSlugs = prepData.existingSlugs || [];
if (existingSlugs.includes(slug)) {
  slug = slug + '-' + Date.now().toString().slice(-4);
}

// Construire l'article complet
const fullArticle = {
  slug: slug,
  title: article.title,
  category: article.category || prepData.category,
  date: today,
  image: image,
  readTime: article.readTime || '4 min',
  content: article.content
};

// Construire l'entrée pour articles.json
const indexEntry = {
  slug: slug,
  title: article.title,
  excerpt: article.excerpt || article.title,
  category: article.category || prepData.category,
  date: today,
  image: image,
  readTime: article.readTime || '4 min'
};

return [{
  json: {
    slug: slug,
    title: article.title,
    category: article.category || prepData.category,
    articleType: articleType,
    date: today,
    fullArticle: JSON.stringify(fullArticle, null, 2),
    indexEntry: JSON.stringify(indexEntry),
    fullArticleObj: fullArticle,
    indexEntryObj: indexEntry
  }
}];

// Récupérer le contenu actuel de articles.json
const githubData = $input.first().json;
let currentContent;
if (typeof githubData.content === 'string') {
  try {
    currentContent = Buffer.from(githubData.content, 'base64').toString('utf8');
  } catch(e) {
    currentContent = githubData.content;
  }
} else {
  currentContent = JSON.stringify(githubData.content);
}
const articles = JSON.parse(currentContent);

// Récupérer le nouvel article depuis le noeud 'Parser réponse Claude'
const parseData = $('Parser réponse Claude').first().json;
const newEntry = JSON.parse(parseData.indexEntry);

// Ajouter au début du tableau (plus récent en premier)
articles.unshift(newEntry);

// Retourner le contenu mis à jour
return [{
  json: {
    updatedContent: JSON.stringify(articles, null, 2),
    sha: githubData.sha
  }
}];
